import numpy as np

def meshgrid(xi, indexing, sparse, copy_):
    ndim = len(xi)
    s0 = (1,) * ndim

    output = []
    for i, x in enumerate(xi):
        arr = np.asarray(x)
        shape = s0[:i] + (-1,) + s0[i+1:]
        output.append(arr.reshape(shape))

    shape = [x.size for x in output]

    if indexing == 'xy' and ndim > 1:
        output[0] = output[0].reshape(1, -1)
        output[1] = output[1].reshape(-1, 1)
        shape[0], shape[1] = shape[1], shape[0]

    if sparse:
        if copy_:
            return [x.copy() for x in output]
        else:
            return output
    else:
        mult_fact = np.ones(shape, dtype=int)
        if copy_:
            return [x * mult_fact for x in output]
        else:
            return list(np.broadcast_arrays(*output))
