from scipy import signal

def idxsOfRelativeExtrema(x, maxima, allowEq, axis):
    # Input validation
    if len(x) == 0:
        return np.array([None])

    if len(x) == 1:
        return np.array([0])

    # Array conversion
    x = np.array(x)

    # Padding determination
    if maxima:
        pad = -np.inf
    else:
        pad = np.inf

    # Comparison function selection
    if maxima and allowEq:
        cmp_func = np.greater_equal
    elif maxima and not allowEq:
        cmp_func = np.greater
    elif not maxima and allowEq:
        cmp_func = np.less_equal
    else:
        cmp_func = np.less

    # Handling one-dimensional input
    if x.ndim == 1:
        x_padded = np.append(x, pad)
        indices = signal.argrelextrema(x_padded, cmp_func, mode='wrap')[0]
        # Filter out indices that are out of bounds for original array
        indices = indices[indices < len(x)]
        return indices

    # Handling two-dimensional input
    elif x.ndim == 2:
        if axis == 0:
            # Pad along rows (add a row of pad values at the end)
            pad_row = np.full((1, x.shape[1]), pad)
            x_padded = np.vstack([x, pad_row])
            indices = signal.argrelextrema(x_padded, cmp_func, axis=0, mode='wrap')
            # Filter indices that are within original array bounds
            valid_mask = indices[0] < x.shape[0]
            return tuple(idx[valid_mask] for idx in indices)

        elif axis == 1:
            # Pad along columns (add a column of pad values at the end)
            pad_col = np.full((x.shape[0], 1), pad)
            x_padded = np.hstack([x, pad_col])
            indices = signal.argrelextrema(x_padded, cmp_func, axis=1, mode='wrap')
            # Filter indices that are within original array bounds
            valid_mask = indices[1] < x.shape[1]
            return tuple(idx[valid_mask] for idx in indices)

    return np.array([])


