import numpy as np

def _mask_to_limits(a, limits, inclusive):
    lower, upper = limits
    lower_inc, upper_inc = inclusive

    if lower_inc:
        lower_mask = a < lower
    else:
        lower_mask = a <= lower

    if upper_inc:
        upper_mask = a > upper
    else:
        upper_mask = a >= upper

    mask = lower_mask | upper_mask
    return np.ma.MaskedArray(a, mask=mask)

def tsem(a, limits, inclusive, axis, ddof):
    a = np.asarray(a).ravel()

    if limits is None:
        if a.size > 0:
            return a.std(ddof=ddof) / np.sqrt(a.size)
        else:
            return np.nan

    am = _mask_to_limits(a, limits, inclusive)

    count = am.count(axis=axis)

    if count == 0:
        return np.nan

    var = np.ma.var(am, ddof=ddof, axis=axis)

    sem = np.sqrt(var) / np.sqrt(count)

    return sem

