def to_dataframe(ifp: dict, interactions: list, count: bool, dtype: type, drop_empty: bool, index_col: str) -> pd.DataFrame:
    # Determine data type and empty value
    if dtype is None:
        dtype = np.uint8 if count else bool

    if count:
        empty_value = 0
    else:
        empty_value = False

    # Identify unique residue pairs (sorted)
    residue_pairs = sorted(set(
        pair for frame_data in ifp.values() for pair in frame_data.keys()
    ))

    # Initialize data storage
    data = {pair: [] for pair in residue_pairs}
    index = []

    # Iterate over frames
    for frame, ifp_dict in ifp.items():
        index.append(frame)
        for pair in residue_pairs:
            pair_data = ifp_dict.get(pair, {})
            if count:
                bitvector = np.array([
                    len(pair_data.get(interaction, ())) for interaction in interactions
                ], dtype=dtype)
            else:
                bitvector = np.array([
                    interaction in pair_data and len(pair_data[interaction]) > 0
                    for interaction in interactions
                ], dtype=dtype)
            data[pair].append(bitvector)

    # Construct 2D numpy array by stacking bitvectors
    # For each frame, concatenate all pair bitvectors
    values_list = []
    for i in range(len(index)):
        row = np.concatenate([data[pair][i] for pair in residue_pairs])
        values_list.append(row)

    values = np.array(values_list, dtype=dtype)

    # Create MultiIndex for columns
    tuples = []
    for pair in residue_pairs:
        ligand, protein = pair
        for interaction in interactions:
            tuples.append((ligand, protein, interaction))

    columns = pd.MultiIndex.from_tuples(tuples, names=['ligand', 'protein', 'interaction'])

    # Create DataFrame
