import numpy as np

def augment_img(img: np.ndarray, mode: int) -> np.ndarray:
    # Check if image is empty or not 2D
    if img.size == 0 or img.ndim != 2:
        return img

    if mode == 0:
        return img
    elif mode == 1:
        return np.rot90(np.flipud(img), k=1)
    elif mode == 2:
        return np.flipud(img)
    elif mode == 3:
        return np.rot90(img, k=3)
    elif mode == 4:
        return np.rot90(np.flipud(img), k=2)
    elif mode == 5:
        return np.rot90(img, k=1)
    elif mode == 6:
        return np.rot90(img, k=2)
    elif mode == 7:
        return np.rot90(np.flipud(img), k=3)
    else:
        return img
