import numpy as np

def rankdata(a, method):
    a = np.ravel(np.asarray(a))

    if method == 'ordinal':
        sorter = np.argsort(a, kind='mergesort')
    else:
        sorter = np.argsort(a, kind='quicksort')

    inv = np.empty(len(a), dtype=np.intp)
    inv[sorter] = np.arange(len(a), dtype=np.intp)

    if method == 'ordinal':
        return (inv + 1).astype('float64')

    a_sorted = a[sorter]
    obs = np.empty(len(a), dtype=bool)
    obs[0] = True
    obs[1:] = a_sorted[1:] != a_sorted[:-1]

    dense = np.cumsum(obs)[inv]

    if method == 'dense':
        return dense.astype('float64')

    # count is the number of elements up to and including each unique value
    count = np.concatenate((np.nonzero(obs)[0], [len(obs)]))

    if method == 'max':
        return count[dense].astype('float64')

    if method == 'min':
        return (count[dense - 1] + 1).astype('float64')

    # default: average
    return (0.5 * (count[dense] + count[dense - 1] + 1)).astype('float64')
