import numpy as np

def logbins_numba(lo: float, hi: float, ratio: float, N: int, prepend_zero: bool) -> np.ndarray:
    # Step 1: Convert bounds to integers
    lo = int(lo)
    hi = int(hi)

    # Step 2: Determine number of points N
    if ratio != 0 and N == 0:
        N = np.log(hi / lo) / np.log(ratio)

    if N == 0:
        N = 10

    # Step 3: Ensure minimum points
    N = max(1, int(N))

    # Step 4: Generate logarithmic sequence
    log_lo = np.log10(lo)
    log_hi = np.log10(hi)
    sequence = np.logspace(log_lo, log_hi, N)
    sequence = np.round(sequence).astype(int)

    # Step 5: Unique and sorted values
    sequence = np.unique(sequence)

    # Step 6: Boundary conditions
    if len(sequence) == 0:
        if prepend_zero:
            return np.array([0])
        else:
            return np.array([])

    if sequence[0] != lo:
        sequence = np.concatenate(([lo], sequence))

    if sequence[-1] != hi:
        sequence = np.concatenate((sequence, [hi]))

    # Step 7: Prepend zero if needed
    if prepend_zero:
        sequence = np.concatenate(([0], sequence))

    # Step 8: Return result
    return sequence
