import pandas as pd
import numpy as np

def reduce_mem_usage(df):
    start_mem_usg = df.memory_usage().sum() / 1024**2

    NAlist = []

    for col in df.columns:
        if df[col].dtype != object:
            # Check for NaN or infinite values
            has_nan = df[col].isna().any()
            has_inf = np.isinf(df[col]).any()

            if has_nan or has_inf:
                NAlist.append(col)
                # Find minimum finite value
                finite_vals = df[col][np.isfinite(df[col])]
                if len(finite_vals) > 0:
                    min_finite = finite_vals.min()
                else:
                    min_finite = np.nan

                if np.isfinite(min_finite):
                    replace_val = min_finite
                else:
                    replace_val = 0

                df[col] = df[col].replace([np.inf, -np.inf], np.nan)
                df[col] = df[col].fillna(replace_val)

            # Check if column can be treated as integer
            col_min = df[col].min()
            col_max = df[col].max()

            rounded = df[col].round()
            if abs((df[col] - rounded).sum()) < 0.01:
                # Integer type
                if col_min >= 0:
                    if col_max <= 255:
                        df[col] = df[col].astype(np.uint8)
                    elif col_max <= 65535:
                        df[col] = df[col].astype(np.uint16)
                    elif col_max <= 4294967295:
                        df[col] = df[col].astype(np.uint32)
                    else:
                        df[col] = df[col].astype(np.uint64)
                else:
                    if col_min >= np.iinfo(np.int8).min and col_max <= np.iinfo(np.int8).max:
                        df[col] = df[col].astype(np.int8)
                    elif col_min >= np.iinfo(np.int16).min and col_max <= np.iinfo(np.int16).max:
                        df[col] = df[col].astype(np.int16)
                    elif col_min >= np.iinfo(np.int32).min and col_max <= np.iinfo(np.int32).max:
                        df[col] = df[col].astype(np.int32)
                    else:
                        df[col] = df[col].astype(np.int64)
            else:
                # Float type
                df[col] = df[col].astype(np.float32)

    end_mem_usg = df.memory_usage().sum() / 1024**2

    if start_mem_usg > 0:
        mem_usg_percentage = (1 - end_mem_usg / start_mem_usg) * 100
    else:
        mem_usg_percentage = 0.0

    return df, NAlist, mem_usg_percentage
