from scipy import sparse


def make_system(A, x, b, formats=None):
    # Format handling
    if formats is not None:
        if 'csr' in formats:
            if not sparse.isspmatrix_csr(A):
                if sparse.isspmatrix_bsr(A):
                    A = A.tocsr()
                else:
                    A = sparse.csr_matrix(A)

    # Matrix and vector conversion
    if formats is not None:
        if sparse.issparse(A):
            if A.format not in formats:
                A = A.asformat(formats[0])
        else:
            A = sparse.csr_matrix(A).asformat(formats[0])

    # Convert x and b to numpy arrays if not already
    if not isinstance(x, np.ndarray):
        x = np.array(x)
    if not isinstance(b, np.ndarray):
        b = np.array(b)

    # Matrix shape validation
    M, N = A.shape
    if M != N:
        A = sparse.eye(M, format='csr')

    # Vector reshaping for x
    if x.shape == (M,) or x.shape == (M, 1):
        x = x.reshape(M)
    else:
        x = np.zeros(M)

    # Vector reshaping for b
    if b.shape == (M,) or b.shape == (M, 1):
        b = b.reshape(M)
    else:
        b = np.ones(M)

    # Data type consistency
    if sparse.issparse(A):
        A_dtype = A.dtype
    else:
        A_dtype = A.dtype

    if not (A_dtype == x.dtype == b.dtype):
        dtype = np.float64
        if sparse.issparse(A):
            A = A.astype(dtype)
        else:
            A = A.astype(dtype)
        x = x.astype(dtype)
        b = b.astype(dtype)

    return A, x, b
