import pandas as pd
import numpy as np
from sklearn.metrics import roc_auc_score, average_precision_score
from sklearn.linear_model import LogisticRegression
from scipy import stats

def compute_roc_metrics(df, outcome, predictor, model_predictors=None, n_bootstraps=200):
    results = {}
    y = df[outcome].values

    if model_predictors is None:
        scores = df[predictor].values
    else:
        # Fit logistic regression using cross-validation folds
        scores = np.zeros(len(df))
        folds = df['cv_linear'].unique()
        for fold in folds:
            train_idx = df['cv_linear'] != fold
            test_idx = df['cv_linear'] == fold
            X_train = df.loc[train_idx, model_predictors].values
            y_train = df.loc[train_idx, outcome].values
            X_test = df.loc[test_idx, model_predictors].values
            if len(np.unique(y_train)) < 2:
                scores[test_idx] = 0.5
            else:
                clf = LogisticRegression(max_iter=1000)
                clf.fit(X_train, y_train)
                scores[test_idx] = clf.predict_proba(X_test)[:, 1]

    # Compute base metrics
    corr_r, corr_p = stats.pearsonr(scores, y) if len(scores) > 2 else (np.nan, np.nan)
    try:
        auc = roc_auc_score(y, scores)
    except:
        auc = np.nan
    try:
        prc = average_precision_score(y, scores)
    except:
        prc = np.nan
    mean_outcome = np.mean(y)

    # Bootstrap confidence intervals
    boot_corr_r, boot_corr_p, boot_auc, boot_prc = [], [], [], []
    rng = np.random.RandomState(42)
    for _ in range(n_bootstraps):
        idx = rng.choice(len(y), len(y), replace=True)
        y_boot = y[idx]
        s_boot = scores[idx]
        if len(np.unique(y_boot)) < 2:
            continue
        try:
            r, p = stats.pearsonr(s_boot, y_boot)
            boot_corr_r.append(r)
            boot_corr_p.append(p)
        except:
            pass
        try:
            boot_auc.append(roc_auc_score(y_boot, s_boot))
        except:
            pass
        try:
            boot_prc.append(average_precision_score(y_boot, s_boot))
        except:
            pass

    def fmt(val, low, high):
        return f'{val:.3f} ({low:.3f} - {high:.3f})'

    def ci(lst):
        if len(lst) == 0:
            return np.nan, np.nan
        return np.percentile(lst, 2.5), np.percentile(lst, 97.5)

    cr_lo, cr_hi = ci(boot_corr_r)
    cp_lo, cp_hi = ci(boot_corr_p)
    a_lo, a_hi = ci(boot_auc)
    p_lo, p_hi = ci(boot_prc)

    results['correlation_r'] = fmt(corr_r, cr_lo, cr_hi)
    results['correlation_p'] = fmt(corr_r, cr_lo, cr_hi)
    results['auc'] = fmt(auc, a_lo, a_hi)
    results['prc'] = fmt(prc, p_lo, p_hi)
    results['mean_outcome'] = f'{mean_outcome:.3f}'

    return results


def compute_roc(df1, outcome: str, clin_predictor: str, avg_coefs: bool) -> dict:
    df = df1.copy()
    results = {}

    if avg_coefs:
        n_bootstraps = 200

        # Metrics for percent_tiles_positive0 alone
        results['percent_tiles_positive0'] = compute_roc_metrics(
            df, outcome, 'percent_tiles_positive0', model_predictors=None, n_bootstraps=n_bootstraps
        )

        # Metrics for clin_predictor alone (only add if different from percent_tiles_positive0)
        if clin_predictor != 'percent_tiles_positive0':
            results[clin_predictor] = compute_roc_metrics(
                df, outcome, clin_predictor, model_predictors=None, n_bootstraps=n_bootstraps
            )

        # Metrics for combined model
        if clin_predictor != 'percent_tiles_positive0':
            model_predictors = ['percent_tiles_positive0', clin_predictor]
        else:
            model_predictors = ['percent_tiles_positive0']

        results['comb'] = compute_roc_metrics(
            df, outcome, None, model_predictors=model_predictors, n_bootstraps=n_bootstraps
        )

    else:
        for predictor in ['percent_tiles_positive0', 'ten_score', 'comb']:
            y = df[outcome].values
            if predictor == 'comb':
                scores = df[['percent_tiles_positive0', 'ten_score']].mean(axis=1).values
            else:
                scores = df[predictor].values
            try:
                auc = roc_auc_score(y, scores)
            except:
                auc = np.nan
            results[f'auc_{predictor}'] = auc

    return results
