        y_train = y_train.squeeze(axis=-1)
    if len(y_test.shape) == 3:
        y_test = y_test.squeeze(axis=-1)

    # Single Output Case
    if y_test.shape[-1] == 1:
        models = {
            "GCN+rf": RandomForestRegressor(),
            "GCN+svm": svm.SVR(C=C),
            "GCN+knn": KNeighborsRegressor()
        }

        y_train_flat = y_train.ravel()
        y_test_flat = y_test.ravel()

        for model_name, model in models.items():
            model.fit(X_train, y_train_flat)
            y_pred = model.predict(X_test)
            rmse = np.sqrt(mean_squared_error(y_test_flat, y_pred))
            scores.append({"Model": model_name, "RMSE": rmse})

    else:
        # Multi-Output Case
        results = {
            "GCN+rf": [],
            "GCN+svm": [],
            "GCN+knn": []
        }

        num_outputs = y_test.shape[-1]

        for i in range(num_outputs):
            y_train_i = y_train[:, i]
            y_test_i = y_test[:, i]

            if np.max(y_train_i) == 0 or np.max(y_test_i) == 0:
                continue

            models = {
                "GCN+rf": RandomForestRegressor(),
                "GCN+svm": svm.SVR(C=C),
                "GCN+knn": KNeighborsRegressor()
            }

            for model_name, model in models.items():
                model.fit(X_train, y_train_i)
                y_pred = model.predict(X_test)
                rmse = np.sqrt(mean_squared_error(y_test_i, y_pred))
                results[model_name].append(rmse)

        for model_name, rmse_list in results.items():
            if rmse_list:
                mean_rmse = np.mean(rmse_list)
                scores.append({"Model": model_name, "RMSE": mean_rmse})

    if not scores:
        return pd.DataFrame()

    return pd.DataFrame(scores, columns=["Model", "RMSE"])
