def get_variable_from_tensor(var):
    # Check if var is already a TensorFlow Variable
    if isinstance(var, tf.Variable):
        return var

    # Check if var is a TensorFlow Tensor
    if isinstance(var, tf.Tensor):
        # Check if the tensor has an 'op' attribute and if the op type is 'ReadVariableOp'
        if hasattr(var, 'op') and var.op.type == 'ReadVariableOp':
            var = var.op.inputs[0]

        # Check if the op type is 'VarHandleOp' or 'VariableV2'
        if hasattr(var, 'op') and var.op.type in ('VarHandleOp', 'VariableV2'):
            # Iterate through all global variables to find a match
            for global_var in tf.compat.v1.global_variables():
                if global_var.handle is var or global_var.handle.op is var.op:
                    return global_var
            return None

        # Check if the op type is 'Identity'
        if hasattr(var, 'op') and var.op.type == 'Identity':
            var = var.op.inputs[0]
            return get_variable_from_tensor(var)

