import tensorflow as tf


def expand_multiple_dims(value, num_dims):
    """Expand dimensions of value to match num_dims by adding dimensions at the end."""
    for _ in range(num_dims - len(value.shape)):
        value = tf.expand_dims(value, axis=-1)
    return value


def unbroadcast_to_common_shape(value, common_shape, ignore_axes=(), allow_only_noop=False):
    # Check if value is a TensorFlow tensor
    if not isinstance(value, tf.Tensor):
        # Check if value is a scalar and common_shape is empty
        if isinstance(value, (float, int)) and len(common_shape) == 0:
            return value
        # Convert value to tensor
        value = tf.convert_to_tensor(value)

    # Determine number of dimensions
    ndim = len(value.shape)
    if ndim is None:
        ndim = len(common_shape)

    # Handle scalar case
    if ndim == 0:
        value = expand_multiple_dims(value, len(common_shape))
        ndim = len(common_shape)

    # Calculate tile multiples
    tile_multiples = []
    value_shape = value.shape.as_list()

    for i in range(ndim):
        if i < len(value_shape) and value_shape[i] == 1:
            if i < len(common_shape):
                tile_multiples.append(common_shape[i])
            else:
                tile_multiples.append(1)
        else:
            tile_multiples.append(1)

    # Ignore specified axes
    for axis in ignore_axes:
        if 0 <= axis < len(tile_multiples):
            tile_multiples[axis] = 1

    # Check for no-operation
    if all(m == 1 for m in tile_multiples):
        return value

    # Tile the tensor if allow_only_noop is False
    if not allow_only_noop:
        value = tf.tile(value, tile_multiples)

    return value


