def evaluate(model, test_iter, loss_fn):
    epoch_loss = 0.0
    epoch_accuracy = 0.0
    model.eval()
    steps = 0

    with torch.no_grad():
        for batch in test_iter:
            inputs, targets = batch

            if inputs.size(0) != 32:
                continue

            likelihood = model(inputs)

            loss = loss_fn(likelihood, targets)
            epoch_loss += loss.item()

            _, predicted = torch.max(likelihood, dim=1)
            correct = (predicted == targets).sum().item()
            accuracy = (correct / inputs.size(0)) * 100.0
            epoch_accuracy += accuracy

            steps += 1

    if steps == 0:
        return (0.0, 0.0)

    return (epoch_loss / steps, epoch_accuracy / steps)


